final:
module top_module(D,CLK,RSTB,Q,QN);input D;
 input CLK;
 input RSTB;
 output Q;
 output QN;

 reg unused_Qtemp;

 always @(posedge CLK or negedge RSTB) begin
   if (~RSTB) begin
     unused_Qtemp <= 1'b0;
   end else begin
     unused_Qtemp <= D;
   end
 end

 assign QN = ~unused_Qtemp;
 assign Q = unused_Qtemp;

endmodule
